INSERT INTO "NPC" (id, "campaignId", name, aliases, status, gender, age, species, "speciesId", appearance, personality, description, motivation, flaws, "gmNotes", "createdAt", "updatedAt") VALUES ('npc-drexel', 'campaign-drakkenheim', 'Elias Drexel', ARRAY['Элиас Дресель'], 'ALIVE', 'MALE', 47, 'Human', 'species-human', NULL, 'Военный до мозга костей: дисциплинирован, лаконичен, миссия прежде всего. Не говорит лишнего — каждое слово взвешено. Уважает тех, кто держит слово. Усталость от войны скрывает за строгим лицом.', 'Командор Фонарей (The Hooded Lanterns). Союзник партии.', NULL, NULL, NULL, NOW(), NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO "NPCGroupMembership" (id, "npcId", "groupId", relation, subfaction) VALUES (gen_random_uuid(), 'npc-drexel', 'faction-dk-lanterns', 'Leader', NULL) ON CONFLICT ("npcId", "groupId") DO NOTHING;
INSERT INTO "NPC" (id, "campaignId", name, aliases, status, gender, age, species, "speciesId", appearance, personality, description, motivation, flaws, "gmNotes", "createdAt", "updatedAt") VALUES ('npc-ansom-lang', 'campaign-drakkenheim', 'Ansom Lang', ARRAY['Ансом Лэнг'], 'ALIVE', 'MALE', 28, 'Human', 'species-human', NULL, NULL, 'Член Фонарей. Хочет восстановить старый город, столицу и нацию. Брат Петры Лэнг. В сессии 5 попросил спасти сестру — выполнено в сессии 7.', NULL, NULL, NULL, NOW(), NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO "NPCGroupMembership" (id, "npcId", "groupId", relation, subfaction) VALUES (gen_random_uuid(), 'npc-ansom-lang', 'faction-dk-lanterns', 'Member', NULL) ON CONFLICT ("npcId", "groupId") DO NOTHING;
INSERT INTO "NPC" (id, "campaignId", name, aliases, status, gender, age, species, "speciesId", appearance, personality, description, motivation, flaws, "gmNotes", "createdAt", "updatedAt") VALUES ('npc-petra-lang', 'campaign-drakkenheim', 'Petra Lang', ARRAY['Петра Лэнг'], 'ALIVE', 'FEMALE', 26, 'Human', 'species-human', NULL, NULL, 'Сестра Ансома Лэнга. Пропала в патруле, захвачена крысами. Спасена партией из Крысиного гнезда (сессия 7). Рассказала, что Аметисты скрывают секрет про Оскара Йорена.', NULL, NULL, NULL, NOW(), NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO "NPCGroupMembership" (id, "npcId", "groupId", relation, subfaction) VALUES (gen_random_uuid(), 'npc-petra-lang', 'faction-dk-lanterns', 'Member', NULL) ON CONFLICT ("npcId", "groupId") DO NOTHING;
INSERT INTO "NPC" (id, "campaignId", name, aliases, status, gender, age, species, "speciesId", appearance, personality, description, motivation, flaws, "gmNotes", "createdAt", "updatedAt") VALUES ('npc-raine', 'campaign-drakkenheim', 'Raine Highlash', ARRAY['Рейн Харлаш'], 'ALIVE', 'FEMALE', 34, 'Human', 'species-human', NULL, NULL, 'Капитан дозора Фонарей в Часовой башне Эмбервуда. Первая встреча в сессии 1.', NULL, NULL, NULL, NOW(), NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO "NPCGroupMembership" (id, "npcId", "groupId", relation, subfaction) VALUES (gen_random_uuid(), 'npc-raine', 'faction-dk-lanterns', 'Member', NULL) ON CONFLICT ("npcId", "groupId") DO NOTHING;
INSERT INTO "NPC" (id, "campaignId", name, aliases, status, gender, age, species, "speciesId", appearance, personality, description, motivation, flaws, "gmNotes", "createdAt", "updatedAt") VALUES ('npc-rosa-carver', 'campaign-drakkenheim', 'Rosa Carver', ARRAY['Роза Карвер'], 'HOSTILE', 'FEMALE', 36, 'Human', 'species-human', 'Рыжеволосая женщина-воин в тёмной броне.', 'Деловая и беспощадная — без лишних слов. Улыбается ровно столько, сколько нужно для сделки. Уважает силу и ненавидит сантименты. Никогда не угрожает дважды.', 'Босс «Розы и Шипов» — подгруппы Людей Королевы. База в Старом Имперском Пабе и Прогнутом ряду.', NULL, NULL, NULL, NOW(), NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO "NPCGroupMembership" (id, "npcId", "groupId", relation, subfaction) VALUES (gen_random_uuid(), 'npc-rosa-carver', 'faction-dk-queens', 'Leader', 'Rose and Thorns') ON CONFLICT ("npcId", "groupId") DO NOTHING;
INSERT INTO "NPC" (id, "campaignId", name, aliases, status, gender, age, species, "speciesId", appearance, personality, description, motivation, flaws, "gmNotes", "createdAt", "updatedAt") VALUES ('npc-kristian-lam', 'campaign-drakkenheim', 'Kristian Lam', ARRAY['Кристиан Лам'], 'ALIVE', 'MALE', 42, 'Human', 'species-human', NULL, NULL, 'Босс «Раненых сердец» — подгруппы Людей Королевы. База в Дворце Сми и Прогнутом ряду. Полная фамилия неизвестна.', NULL, NULL, NULL, NOW(), NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO "NPCGroupMembership" (id, "npcId", "groupId", relation, subfaction) VALUES (gen_random_uuid(), 'npc-kristian-lam', 'faction-dk-queens', 'Leader', 'Wounded Hearts') ON CONFLICT ("npcId", "groupId") DO NOTHING;
INSERT INTO "NPC" (id, "campaignId", name, aliases, status, gender, age, species, "speciesId", appearance, personality, description, motivation, flaws, "gmNotes", "createdAt", "updatedAt") VALUES ('npc-veronika-yad', 'campaign-drakkenheim', 'Veronika Yad', ARRAY['Вероника Яд','Veronica Poison'], 'ALIVE', 'FEMALE', 31, 'Human', 'species-human', 'Мрачная женщина с тёмными волосами.', NULL, 'Босс «Канализационных кобр» — подгруппы Людей Королевы. База в Прогнутом ряду. Встречена в сессии 17 в Потном Багбире.', NULL, NULL, NULL, NOW(), NOW()) ON CONFLICT (id) DO NOTHING;
