INSERT INTO "NPC" (id, "campaignId", name, aliases, status, gender, age, species, "speciesId", appearance, personality, description, motivation, flaws, "gmNotes", "createdAt", "updatedAt") VALUES ('npc-dorian', 'campaign-drakkenheim', 'Dorian Derzky', ARRAY['Дориан Дерзкий','Dorian the Bold'], 'ALIVE', 'MALE', 64, 'Human', 'species-human', 'Пожилой мужчина с седой бородой, видавший виды.', NULL, 'Боец на арене в Прогнутом ряду. Раненые сердца.', NULL, NULL, NULL, NOW(), NOW()) ON CONFLICT (id) DO NOTHING;
