INSERT INTO "NPC" (id, "campaignId", name, aliases, status, gender, age, species, "speciesId", appearance, personality, description, motivation, flaws, "gmNotes", "createdAt", "updatedAt") VALUES ('npc-tony', 'campaign-drakkenheim', 'Tony', ARRAY['Тони'], 'ALIVE', 'MALE', 36, 'Human', 'species-human', 'Массивный, грузный, страшноватый на вид.', NULL, '«Вечно спящий охранник Тига» — охраняет кого-то по имени Тига. Прогнутый ряд. Группа неизвестна.', NULL, NULL, NULL, NOW(), NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO "NPCGroupMembership" (id, "npcId", "groupId", relation, subfaction) VALUES (gen_random_uuid(), 'npc-tony', 'faction-dk-queens', 'Member', NULL) ON CONFLICT ("npcId", "groupId") DO NOTHING;
INSERT INTO "NPC" (id, "campaignId", name, aliases, status, gender, age, species, "speciesId", appearance, personality, description, motivation, flaws, "gmNotes", "createdAt", "updatedAt") VALUES ('npc-eldric', 'campaign-drakkenheim', 'Eldric Runeweaver', ARRAY['Элдрик Руноткач'], 'ALIVE', 'MALE', 53, 'Human', 'species-human', NULL, NULL, 'Руководит местным конклавом Аметистовой Академии. В башне во время падения метеорита находился главный маг с посохом (тем самым). Скрывает информацию об Оскаре Йорене.', NULL, NULL, 'Ключевая фигура тайны с Оскаром. Что он знает?', NOW(), NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO "NPCGroupMembership" (id, "npcId", "groupId", relation, subfaction) VALUES (gen_random_uuid(), 'npc-eldric', 'faction-dk-amethyst', 'Leader', NULL) ON CONFLICT ("npcId", "groupId") DO NOTHING;
INSERT INTO "NPC" (id, "campaignId", name, aliases, status, gender, age, species, "speciesId", appearance, personality, description, motivation, flaws, "gmNotes", "createdAt", "updatedAt") VALUES ('npc-river', 'campaign-drakkenheim', 'River', ARRAY['Река'], 'ALIVE', 'FEMALE', 28, 'Tiefling', 'species-tiefling', NULL, 'Острая, закрытая, снисходительна к тем, кто ей нравится — и это почти комплимент. Говорит с ленцой, но слушает внимательно. Держит дистанцию и раздражается, когда её нарушают.', 'Тифлинг-варлок. Управляет отделением Аметистов в Эмбервуде. По ночам зависает в отдельной библиотеке Красного Льва. Прагматична как чёрт. Странно реагирует на имя Оскар Йорен. Поделилась точкой про Мельницу Эккермена. Отправляла телепатические сообщения.', NULL, NULL, 'Почему неприязнь к Йорену? Она что-то знает или сама замешана?', NOW(), NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO "NPCGroupMembership" (id, "npcId", "groupId", relation, subfaction) VALUES (gen_random_uuid(), 'npc-river', 'faction-dk-amethyst', 'Member', NULL) ON CONFLICT ("npcId", "groupId") DO NOTHING;
INSERT INTO "NPC" (id, "campaignId", name, aliases, status, gender, age, species, "speciesId", appearance, personality, description, motivation, flaws, "gmNotes", "createdAt", "updatedAt") VALUES ('npc-sebastian', 'campaign-drakkenheim', 'Sebastian', ARRAY['Себастьян'], 'ALIVE', 'MALE', 24, 'Human', 'species-human', NULL, NULL, 'Ученик Оскара Йорена. Ушёл из Аметистовой Академии. Украл тома по вызову, некромантии и, возможно, трансмутации. Его перестали финансировать. Группа: Марко, Джемма, Таррин, Болтер, Копперпот.', NULL, NULL, 'Связан ли с заражёнными зельями? Куда ушёл после Академии?', NOW(), NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO "NPC" (id, "campaignId", name, aliases, status, gender, age, species, "speciesId", appearance, personality, description, motivation, flaws, "gmNotes", "createdAt", "updatedAt") VALUES ('npc-oscar-yoren', 'campaign-drakkenheim', 'Oscar Yoren', ARRAY['Оскар Йорен','Оскар'], 'UNKNOWN', 'MALE', 52, 'Human', 'species-human', NULL, 'Параноик-гений. Работает в изоляции по собственному выбору. Никому не доверяет достаточно долго. Способен быть обаятельным, когда ему что-то нужно. Его исчезновение — не случайность.', 'Бывший? член Аметистовой Академии. Река знает где он — но молчит. Элдрик Руноткач скрывает информацию. Себастьян — его ученик. Иоганн Призроткач имел с ним дела. Связан с заражёнными зельями чистоты (квест Фонарей).', NULL, NULL, 'ЦЕНТРАЛЬНАЯ ТАЙНА КАМПАНИИ. Что скрывают Аметисты? Жив ли он вообще?', NOW(), NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO "NPCGroupMembership" (id, "npcId", "groupId", relation, subfaction) VALUES (gen_random_uuid(), 'npc-oscar-yoren', 'faction-dk-amethyst', 'Member', NULL) ON CONFLICT ("npcId", "groupId") DO NOTHING;
INSERT INTO "NPC" (id, "campaignId", name, aliases, status, gender, age, species, "speciesId", appearance, personality, description, motivation, flaws, "gmNotes", "createdAt", "updatedAt") VALUES ('npc-ghostweaver', 'campaign-drakkenheim', 'Johann Ghostweaver', ARRAY['Иоганн Призроткач'], 'UNKNOWN', 'MALE', 63, 'Human', 'species-human', NULL, NULL, 'Научил Зою лечению от делириума. Имел дела с Оскаром Йореном. Партия его ещё не встречала — нужно найти.', NULL, NULL, 'Ключ к пониманию связи Зоя → Йорен. Где он сейчас?', NOW(), NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO "NPC" (id, "campaignId", name, aliases, status, gender, age, species, "speciesId", appearance, personality, description, motivation, flaws, "gmNotes", "createdAt", "updatedAt") VALUES ('npc-katya-brown', 'campaign-drakkenheim', 'Katya Brown', ARRAY['Катя Браун','Tanya Brown'], 'ALIVE', 'FEMALE', 37, 'Human', 'species-human', NULL, NULL, 'Сокурсница Вермиры. Раньше была в Священном Пламени, но переметнулась к культистам после Резни Магов 15 лет назад. Культистка у Врат Чемпионов. В сессии 13 — отобрала с фанатиками Bag of Holding.', NULL, NULL, NULL, NOW(), NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO "NPCGroupMembership" (id, "npcId", "groupId", relation, subfaction) VALUES (gen_random_uuid(), 'npc-katya-brown', 'faction-dk-flame', 'Member', NULL) ON CONFLICT ("npcId", "groupId") DO NOTHING;
INSERT INTO "NPC" (id, "campaignId", name, aliases, status, gender, age, species, "speciesId", appearance, personality, description, motivation, flaws, "gmNotes", "createdAt", "updatedAt") VALUES ('npc-lucretia', 'campaign-drakkenheim', 'Lucretia Mathias', ARRAY['Лукреция Матиас'], 'ALIVE', 'FEMALE', 44, 'Human', 'species-human', NULL, NULL, 'Возможно управляет культистами Падшего Пламени у Врат Чемпионов. Встречена в сессии 10.', NULL, NULL, NULL, NOW(), NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO "NPCGroupMembership" (id, "npcId", "groupId", relation, subfaction) VALUES (gen_random_uuid(), 'npc-lucretia', 'faction-dk-flame', 'Leader', NULL) ON CONFLICT ("npcId", "groupId") DO NOTHING;
INSERT INTO "NPC" (id, "campaignId", name, aliases, status, gender, age, species, "speciesId", appearance, personality, description, motivation, flaws, "gmNotes", "createdAt", "updatedAt") VALUES ('npc-bryce-landry', 'campaign-drakkenheim', 'Sir Bryce Landry', ARRAY['Брайс Лендри','Bryce Landry'], 'ALIVE', 'MALE', 39, 'Human', 'species-human', NULL, NULL, 'Рыцарь Серебряного Ордена. Захарис его искал — нашли. Корвин попал ему Magic Missile в оба коленных чашечки (сессия 14).', NULL, NULL, NULL, NOW(), NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO "NPCGroupMembership" (id, "npcId", "groupId", relation, subfaction) VALUES (gen_random_uuid(), 'npc-bryce-landry', 'faction-dk-silver', 'Member', NULL) ON CONFLICT ("npcId", "groupId") DO NOTHING;
INSERT INTO "NPC" (id, "campaignId", name, aliases, status, gender, age, species, "speciesId", appearance, personality, description, motivation, flaws, "gmNotes", "createdAt", "updatedAt") VALUES ('npc-tobias-crowe', 'campaign-drakkenheim', 'Tobias Crowe', ARRAY['Тобиас Кроу'], 'ALIVE', 'MALE', 44, 'Human', 'species-human', NULL, NULL, 'Владеет кузней Crowe and Sons в Эмбервуде. Вероятно отец Эммы Кроу. Дорого, но делают на заказ.', NULL, NULL, NULL, NOW(), NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO "NPC" (id, "campaignId", name, aliases, status, gender, age, species, "speciesId", appearance, personality, description, motivation, flaws, "gmNotes", "createdAt", "updatedAt") VALUES ('npc-emma-crowe', 'campaign-drakkenheim', 'Emma Crowe', ARRAY['Эмма Кроу'], 'ALIVE', 'FEMALE', 11, 'Human', 'species-human', 'Рыжеволосая маленькая девочка. Супер энергичная.', NULL, 'Дочка кузнеца Тобиаса. За 1 gp проводит экскурсии по Эмбервуду. Знает слухи.', NULL, NULL, NULL, NOW(), NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO "NPC" (id, "campaignId", name, aliases, status, gender, age, species, "speciesId", appearance, personality, description, motivation, flaws, "gmNotes", "createdAt", "updatedAt") VALUES ('npc-karin-alsberg', 'campaign-drakkenheim', 'Karin Alsberg', ARRAY['Карин Альцберг'], 'ALIVE', 'FEMALE', 42, 'Human', 'species-human', NULL, 'Практична и гостеприимна — без лишней теплоты. Всегда занята, редко сидит. Быстро распознаёт проблемы и решает их до того, как те выросли. Защищает гостей, но не терпит дебоширов.', 'Владелица Bark and Buzzard (Коршун и Ищейка). Есть муж Holger.', NULL, NULL, NULL, NOW(), NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO "NPC" (id, "campaignId", name, aliases, status, gender, age, species, "speciesId", appearance, personality, description, motivation, flaws, "gmNotes", "createdAt", "updatedAt") VALUES ('npc-zoya', 'campaign-drakkenheim', 'Zoya', ARRAY['Зоя'], 'MISSING', 'FEMALE', 72, 'Human', 'species-human', NULL, 'Говорит полуправдами и намёками — не из вредности, а потому что так видит мир. Тихая, но с характером. Её молчание значит больше, чем слова других. Любит Патрикеевну как родную.', 'Старушка-отшельница, поклоняется Старым богам. Не любима в Эмбервуде. Продаёт янтарные шарики. Подруга Патрикеевны. Знает лечение от делириума (научил Иоганн Призроткач). В сессии 17 оказалась допельгангером Крадущего Мысли — настоящая Зоя неизвестно где.', NULL, NULL, 'Где настоящая Зоя? Зачем Крадущий Мысли за ней? Связь с Йореном через Призроткача.', NOW(), NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO "NPC" (id, "campaignId", name, aliases, status, gender, age, species, "speciesId", appearance, personality, description, motivation, flaws, "gmNotes", "createdAt", "updatedAt") VALUES ('npc-aldor', 'campaign-drakkenheim', 'Aldor', ARRAY['Алдор','Алдор Великан','Джинн'], 'ALIVE', 'MALE', 1200, 'Djinn', NULL, NULL, 'Абсолютно транзакционен — ни тепла, ни злобы. Относится к смертным как к контрагентам. Терпелив ровно настолько, насколько выгодно. Сделки — его язык, угрозы — его пунктуация.', 'Джинн. Продаёт магические предметы на ночном рынке. Долг Корвина 500 gp за уничтоженный Bag of Holding — погашен в сессии 17 проклятым огненным мечом. Находится в астрале, нашёл скипетр — предложил обмен. По словам Людей Королевы — заточён в этом месте.', NULL, NULL, 'Скипетр в астрале — что это? Выгодна ли сделка?', NOW(), NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO "NPC" (id, "campaignId", name, aliases, status, gender, age, species, "speciesId", appearance, personality, description, motivation, flaws, "gmNotes", "createdAt", "updatedAt") VALUES ('npc-orson', 'campaign-drakkenheim', 'Orson Fairweather', ARRAY['Орсон Фейрузер'], 'ALIVE', 'MALE', 40, 'Human', 'species-human', NULL, NULL, 'Торговец делириумом на ночном рынке. Маленький контейнер 4 gp, средний 10 gp, большой 20 gp. Партия продала ему делириум за 27 gp (сессия 5).', NULL, NULL, NULL, NOW(), NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO "NPC" (id, "campaignId", name, aliases, status, gender, age, species, "speciesId", appearance, personality, description, motivation, flaws, "gmNotes", "createdAt", "updatedAt") VALUES ('npc-armin', 'campaign-drakkenheim', 'Armin Gainsbury', ARRAY['Армин Гейнсбери'], 'ALIVE', 'MALE', 38, 'Human', 'species-human', NULL, NULL, 'Торгует экипировкой для приключений на рынке Эмбервуда.', NULL, NULL, NULL, NOW(), NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO "NPC" (id, "campaignId", name, aliases, status, gender, age, species, "speciesId", appearance, personality, description, motivation, flaws, "gmNotes", "createdAt", "updatedAt") VALUES ('npc-eren-marlow', 'campaign-drakkenheim', 'Eren Marlow', ARRAY['Эрен Марлоу'], 'ALIVE', 'MALE', 33, 'Human', 'species-human', NULL, NULL, 'Довёз партию до Эмбервуда в сессии 1. Продаёт базовые припасы на рынке. Работает ночью. Может познакомить с Армином Гейнсбери.', NULL, NULL, NULL, NOW(), NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO "NPC" (id, "campaignId", name, aliases, status, gender, age, species, "speciesId", appearance, personality, description, motivation, flaws, "gmNotes", "createdAt", "updatedAt") VALUES ('npc-madam-rochelle', 'campaign-drakkenheim', 'Madam Rochelle', ARRAY['Мадам Рошель'], 'ALIVE', 'FEMALE', 52, 'Human', 'species-human', NULL, 'Рафинированная и наблюдательная. Видит всё, говорит — ничего лишнего. Держит нейтралитет как защитный щит. Умеет создать ощущение, что вы её единственный важный гость.', 'Управляет Gilded Lily (Позолоченная Лилия). Вечера открытых выступлений.', NULL, NULL, NULL, NOW(), NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO "NPC" (id, "campaignId", name, aliases, status, gender, age, species, "speciesId", appearance, personality, description, motivation, flaws, "gmNotes", "createdAt", "updatedAt") VALUES ('npc-antoine-megara', 'campaign-drakkenheim', 'Antoine Megara', ARRAY['Антуан Мегара'], 'ALIVE', 'MALE', 46, 'Human', 'species-human', NULL, NULL, 'Богатый дворянин. Последователь Священного Пламени (не в составе фракции). Прибыл в Дракенхейм по заданию. Партия забрала у него 30 gp (сессия 12). Команда «Прекраснейший Дом Мегара».', NULL, NULL, NULL, NOW(), NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO "NPC" (id, "campaignId", name, aliases, status, gender, age, species, "speciesId", appearance, personality, description, motivation, flaws, "gmNotes", "createdAt", "updatedAt") VALUES ('npc-endra-jansen', 'campaign-drakkenheim', 'Endra Jansen', ARRAY['Эндра Дженсен'], 'ALIVE', 'FEMALE', 27, 'Human', 'species-human', NULL, NULL, 'Из группы Рикарда Воса и Людвика вон Графа. Выжила после превращения Рикарда в монстра.', NULL, NULL, NULL, NOW(), NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO "NPC" (id, "campaignId", name, aliases, status, gender, age, species, "speciesId", appearance, personality, description, motivation, flaws, "gmNotes", "createdAt", "updatedAt") VALUES ('npc-rikard-vos', 'campaign-drakkenheim', 'Rikard Vos', ARRAY['Рикард Восс'], 'DEAD', 'MALE', 31, 'Human', 'species-human', NULL, NULL, 'Первый монстр, которого встретила партия. Потрогал делириум на дороге и начал превращаться в монстра — ночью трансформировался окончательно. Из группы Людвика вон Графа и Эндры Дженсен.', NULL, NULL, NULL, NOW(), NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO "NPC" (id, "campaignId", name, aliases, status, gender, age, species, "speciesId", appearance, personality, description, motivation, flaws, "gmNotes", "createdAt", "updatedAt") VALUES ('npc-ludwig', 'campaign-drakkenheim', 'Ludwig von Graff', ARRAY['Людвик вон Граф'], 'DEAD', 'MALE', 34, 'Human', 'species-human', NULL, NULL, 'Из группы Рикарда Воса и Эндры Дженсен. Погиб на Дороге к Эмбервуду.', NULL, NULL, NULL, NOW(), NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO "NPC" (id, "campaignId", name, aliases, status, gender, age, species, "speciesId", appearance, personality, description, motivation, flaws, "gmNotes", "createdAt", "updatedAt") VALUES ('npc-kosta-stavros', 'campaign-drakkenheim', 'Kosta Stavros', ARRAY['Костос Старвос'], 'DEAD', 'MALE', 51, 'Human', 'species-human', NULL, NULL, 'Бывший владелец Red Lion Hotel. Убит допельгангером — подтверждено. В сессии 11 обнаружено, что он труп.', NULL, NULL, 'Допельгангер занял его место — кто-то ещё может быть заменён?', NOW(), NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO "NPC" (id, "campaignId", name, aliases, status, gender, age, species, "speciesId", appearance, personality, description, motivation, flaws, "gmNotes", "createdAt", "updatedAt") VALUES ('npc-bogdan', 'campaign-drakkenheim', 'Bogdan', ARRAY['Богдан'], 'MISSING', 'MALE', 40, 'Human', 'species-human', NULL, NULL, 'Глава шайки, которая напала на партию в сессии 1. Сбежал во время встречи с монстром на дороге — забрал у кого-то кинжал. Где-то скрывается.', NULL, NULL, 'У кого кинжал? Что планирует?', NOW(), NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO "NPC" (id, "campaignId", name, aliases, status, gender, age, species, "speciesId", appearance, personality, description, motivation, flaws, "gmNotes", "createdAt", "updatedAt") VALUES ('npc-mind-reaper', 'campaign-drakkenheim', 'Mind Reaper', ARRAY['Крадущий Мысли','Допельгангер','Зоя (ложная)'], 'MISSING', 'NONBINARY', NULL, 'Doppelganger', NULL, NULL, NULL, 'Допельгангер. Выдавал себя за Зою в Прогнутом ряду. Спугнут малой иллюзией — сбежал (сессия 17). Зачем притворялся Зоей? Связан ли с фракциями?', NULL, NULL, 'Кто его контролирует? Цель — похитить лечение от делириума?', NOW(), NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO "NPC" (id, "campaignId", name, aliases, status, gender, age, species, "speciesId", appearance, personality, description, motivation, flaws, "gmNotes", "createdAt", "updatedAt") VALUES ('npc-chertyaka', 'campaign-drakkenheim', 'Чертяка', ARRAY['Chertyaka','Черт'], 'MISSING', 'MALE', 7, 'Horse', NULL, NULL, NULL, 'Конь Сая. С партией с первой сессии. Долго не приручался, но потеплел после часовни. Почти наверняка заражён дымкой Дракенхейма — долгое время провёл в/около города. В сессии 17 отпущен на север от Прогнутого ряда перед побегом. Местонахождение неизвестно.', NULL, NULL, '⚠️ Вероятно заражён делириумом. Что с ним будет? Мутирует?', NOW(), NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO "Location" (id, "campaignId", name, aliases, type, "settlementPopulation", biome, "parentLocationId", description, "gmNotes", "createdAt") VALUES ('loc-dk-region', 'campaign-drakkenheim', 'Drakkenheim Region', ARRAY['Регион Дракенхейма'], 'region', NULL, NULL, NULL, 'Регион вокруг разрушенного Дракенхейма. Заражён делириумом. Искажённые мутанты бродят по руинам.', NULL, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO "Location" (id, "campaignId", name, aliases, type, "settlementPopulation", biome, "parentLocationId", description, "gmNotes", "createdAt") VALUES ('loc-dk-emberwood-region', 'campaign-drakkenheim', 'Emberwood Village Region', ARRAY['Регион Эмбервуда'], 'region', NULL, NULL, NULL, 'Регион вокруг Эмбервуда — относительно безопасная зона вдали от делириума.', NULL, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO "Location" (id, "campaignId", name, aliases, type, "settlementPopulation", biome, "parentLocationId", description, "gmNotes", "createdAt") VALUES ('loc-dk-road', 'campaign-drakkenheim', 'Road to Emberwood', ARRAY['Дорога в Эмбервуд'], 'district', NULL, NULL, 'loc-dk-emberwood-region', 'Дорога в Эмбервуд — место первой встречи с делириумом. Здесь Рикард Вос прикоснулся к осколку и превратился в монстра. Богдан сбежал по этой дороге.', NULL, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO "Location" (id, "campaignId", name, aliases, type, "settlementPopulation", biome, "parentLocationId", description, "gmNotes", "createdAt") VALUES ('loc-dk-zoya-house', 'campaign-drakkenheim', 'Zoya House', ARRAY['Домик Зои'], 'building', NULL, NULL, 'loc-dk-emberwood-region', 'Небольшой домик отшельницы Зои за пределами деревни. Её не жалуют в Эмбервуде. Продаёт янтарные шарики, поклоняется Старым богам. Знает лечение от заражения делириумом через Иоганна Призроткача.', NULL, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO "Location" (id, "campaignId", name, aliases, type, "settlementPopulation", biome, "parentLocationId", description, "gmNotes", "createdAt") VALUES ('loc-dk-emberwood', 'campaign-drakkenheim', 'Emberwood Village', ARRAY['Эмбервуд','Emberwood'], 'village', 340, NULL, 'loc-dk-emberwood-region', 'Стартовая деревня, база партии. В раздрае, но относительно безопасна.', NULL, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO "Location" (id, "campaignId", name, aliases, type, "settlementPopulation", biome, "parentLocationId", description, "gmNotes", "createdAt") VALUES ('loc-dk-marketplace', 'campaign-drakkenheim', 'Marketplace', ARRAY['Рынок в Эмбервуд','Emberwood City Centre'], 'district', NULL, NULL, 'loc-dk-emberwood', 'Рынок в центре Эмбервуда. Работает с 10 утра. Ночные торговцы: Эрен Марлоу (припасы), Алдор (магические предметы), Орсон Фейруэзер (делириум и контейнеры).', NULL, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO "Location" (id, "campaignId", name, aliases, type, "settlementPopulation", biome, "parentLocationId", description, "gmNotes", "createdAt") VALUES ('loc-dk-bark', 'campaign-drakkenheim', 'Bark and Buzzard', ARRAY['Коршун и Ищейка'], 'building', NULL, NULL, 'loc-dk-emberwood', 'Рекомендованная таверна. Еда 1gp, домик 2gp за человека. Хозяйка — Карин Альсберг.', NULL, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO "Location" (id, "campaignId", name, aliases, type, "settlementPopulation", biome, "parentLocationId", description, "gmNotes", "createdAt") VALUES ('loc-dk-skull', 'campaign-drakkenheim', 'Skull and Sword Taphouse', ARRAY['Меч и Череп'], 'building', NULL, NULL, 'loc-dk-emberwood', 'Таверна Людей Королевы. Подозрительная атмосфера. Место для контактов с Queen''s Men.', NULL, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO "Location" (id, "campaignId", name, aliases, type, "settlementPopulation", biome, "parentLocationId", description, "gmNotes", "createdAt") VALUES ('loc-dk-red-lion', 'campaign-drakkenheim', 'Red Lion Hotel', ARRAY['Красный Лев'], 'building', NULL, NULL, 'loc-dk-emberwood', 'Дорогущий люксовый отель. Ночь: 25gp, бутылка вина: 100gp. Владелец — Коста Ставрос (теперь мёртв). Река (Аметисты) проводит вечера в отдельной библиотеке.', NULL, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO "Location" (id, "campaignId", name, aliases, type, "settlementPopulation", biome, "parentLocationId", description, "gmNotes", "createdAt") VALUES ('loc-dk-gilded-lily', 'campaign-drakkenheim', 'Gilded Lily', ARRAY['Позолоченная Лилия'], 'building', NULL, NULL, 'loc-dk-emberwood', 'Приятная таверна с музыкальными вечерами. Грог 1gp. Открытый вечер Микра. Владелица — Мадам Рошель.', NULL, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO "Location" (id, "campaignId", name, aliases, type, "settlementPopulation", biome, "parentLocationId", description, "gmNotes", "createdAt") VALUES ('loc-dk-smithy', 'campaign-drakkenheim', 'Crowe and Sons Smithy', ARRAY['Кузня Кроу'], 'building', NULL, NULL, 'loc-dk-emberwood', 'Кузня Тобиаса Кроу. Дорогая, но делают на заказ.', NULL, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO "Location" (id, "campaignId", name, aliases, type, "settlementPopulation", biome, "parentLocationId", description, "gmNotes", "createdAt") VALUES ('loc-dk-chapel', 'campaign-drakkenheim', 'Chapel of Saint Ardenna', ARRAY['Часовня Святой Арденны'], 'building', NULL, NULL, 'loc-dk-emberwood', 'База Рыцарей Серебряного Ордена в Эмбервуде. Центр Священного Пламени.', NULL, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO "Location" (id, "campaignId", name, aliases, type, "settlementPopulation", biome, "parentLocationId", description, "gmNotes", "createdAt") VALUES ('loc-dk-watchtower', 'campaign-drakkenheim', 'Emberwood Watchtower', ARRAY['Часовая Башня','Башня фонарей'], 'building', NULL, NULL, 'loc-dk-emberwood', 'Башня Капюшонных Фонарей — самая высокая постройка в деревне. Охрана у моста, проверка на заражение делириумом. Капитан дозора — Рейн Хайлэш.', NULL, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO "Location" (id, "campaignId", name, aliases, type, "settlementPopulation", biome, "parentLocationId", description, "gmNotes", "createdAt") VALUES ('loc-dk-old-rattlecan', 'campaign-drakkenheim', 'Old Rattlecan', ARRAY['Старый Трещот'], 'building', NULL, NULL, 'loc-dk-emberwood', 'Анимированные доспехи на заднем дворе "Коршуна и Ищейки". Местное развлечение. В сессии 3 местные полезли к нему — Патрикеевна получила по лицу. Кто его создал — неизвестно.', NULL, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO "Location" (id, "campaignId", name, aliases, type, "settlementPopulation", biome, "parentLocationId", description, "gmNotes", "createdAt") VALUES ('loc-dk-eckerman-mill', 'campaign-drakkenheim', 'Eckerman Mill', ARRAY['Мельница Эккермена'], 'building', NULL, NULL, 'loc-dk-region', 'Мельница за пределами Дракенхейма и Эмбервуда. Река когда-то предлагала встретиться здесь. Рядом — заброшенный особняк, место встречи с подозрительной личностью, продающей заражённые зелья (квест Фонарей).', NULL, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO "Location" (id, "campaignId", name, aliases, type, "settlementPopulation", biome, "parentLocationId", description, "gmNotes", "createdAt") VALUES ('loc-dk-city', 'campaign-drakkenheim', 'Drakkenheim', ARRAY['Дракенхейм','Драккенхейм'], 'city', 40000, NULL, 'loc-dk-region', 'Разрушенный город. Место падения метеорита с делириумом. Крайне опасно: заражение, монстры, Искажённые. Река Дран — граница безопасной зоны.', NULL, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO "Location" (id, "campaignId", name, aliases, type, "settlementPopulation", biome, "parentLocationId", description, "gmNotes", "createdAt") VALUES ('loc-dk-house-copperpot', 'campaign-drakkenheim', 'House with Copperpot''s Corpse', ARRAY['Домик с трупом Копперпота'], 'building', NULL, NULL, 'loc-dk-city', 'Место в Дракенхейме с трупом Коксворда Б. Копперпота. Содержит: нерабочий круг телепортации, скрытую записку на неизвестном языке (не расшифрована), надпись на стене.', NULL, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO "Location" (id, "campaignId", name, aliases, type, "settlementPopulation", biome, "parentLocationId", description, "gmNotes", "createdAt") VALUES ('loc-dk-champions-gate', 'campaign-drakkenheim', 'Champion''s Gate', ARRAY['Врата Чемпионов'], 'building', NULL, NULL, 'loc-dk-city', 'Врата в Дракенхейме — место тусовки культистов Падшего Пламени. Здесь обосновалась Лукреция Матиас.', NULL, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO "Location" (id, "campaignId", name, aliases, type, "settlementPopulation", biome, "parentLocationId", description, "gmNotes", "createdAt") VALUES ('loc-dk-bent-row', 'campaign-drakkenheim', 'Bent Row', ARRAY['Прогнутый ряд'], 'district', NULL, NULL, 'loc-dk-city', 'Подземный район Дракенхейма в Районе Спицы за Крысиным гнездом. Логово нескольких группировок Queen''s Men: Собаки, Катакомбные Кобры, Роза и Шипы, Карта-Бубен и Штыри, Раненые Сердца.', NULL, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO "Location" (id, "campaignId", name, aliases, type, "settlementPopulation", biome, "parentLocationId", description, "gmNotes", "createdAt") VALUES ('loc-dk-rat-nest', 'campaign-drakkenheim', 'Rat Nest', ARRAY['Крысиное гнездо'], 'dungeon', NULL, NULL, 'loc-dk-city', 'Гнездо крыс в руинах Дракенхейма. Здесь была заперта Петра Лэнг. Зачищено партией.', NULL, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO "Location" (id, "campaignId", name, aliases, type, "settlementPopulation", biome, "parentLocationId", description, "gmNotes", "createdAt") VALUES ('loc-dk-old-imperial-pub', 'campaign-drakkenheim', 'Old Imperial Pub', ARRAY['Старый Имперский Паб'], 'building', NULL, NULL, 'loc-dk-bent-row', 'Подземная таверна в Прогнутом ряду. База группы «Роза и Шипы» Людей Королевы. Владеет Роза Карвер, бармен — Израэль.', NULL, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO "Location" (id, "campaignId", name, aliases, type, "settlementPopulation", biome, "parentLocationId", description, "gmNotes", "createdAt") VALUES ('loc-dk-sweaty-bugbear', 'campaign-drakkenheim', 'Sweaty Bugbear', ARRAY['Трактир Потный Багбир'], 'building', NULL, NULL, 'loc-dk-bent-row', 'Подземная таверна в Прогнутом ряду. Место Вероники Яд. Здесь партии дали бесплатный стейк как извинение. Патрикеевна попала дротиком в гнома, привязанного к мишени.', NULL, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO "Location" (id, "campaignId", name, aliases, type, "settlementPopulation", biome, "parentLocationId", description, "gmNotes", "createdAt") VALUES ('loc-dk-smis-palace', 'campaign-drakkenheim', 'Smi''s Palace', ARRAY['Дворец Сми'], 'building', NULL, NULL, 'loc-dk-bent-row', 'Подземное заведение в Прогнутом ряду. База группы «Раненые Сердца» Людей Королевы. Хозяин — Кристиан Лам, официантка-эльфийка Тильда. Партия ночевала здесь после сессии 15.', NULL, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO "Location" (id, "campaignId", name, aliases, type, "settlementPopulation", biome, "parentLocationId", description, "gmNotes", "createdAt") VALUES ('loc-dk-arena', 'campaign-drakkenheim', 'Arena', ARRAY['Подземная Арена'], 'dungeon', NULL, NULL, 'loc-dk-bent-row', 'Большая подземная арена в канализации под Прогнутым рядом. Пол в крови и грязи, скамейки для ~40 зрителей, боевое кольцо с деревянными баррикадами, VIP-площадка. Организатор — Булл (обезображенное лицо, один слепой глаз). Ставки принимает полурослик Рокки.', NULL, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO "Quest" (id, "campaignId", title, description, "giverId", reward, status, notes, "createdAt") VALUES ('q-dk-1', 'campaign-drakkenheim', 'Find Oscar Yoren', 'The Amethyst Academy is hiding something about Oscar Yoren.', NULL, NULL, 'UNDISCOVERED', 'What are the Amethysts concealing?', NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO "Quest" (id, "campaignId", title, description, "giverId", reward, status, notes, "createdAt") VALUES ('q-dk-2', 'campaign-drakkenheim', 'Decipher Copperpot''s Note', 'A note found on Copperpot''s corpse written in an unknown language.', 'npc-rosa-carver', NULL, 'UNDISCOVERED', '', NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO "Quest" (id, "campaignId", title, description, "giverId", reward, status, notes, "createdAt") VALUES ('q-dk-3', 'campaign-drakkenheim', 'Find Johann Ghostweaver', 'Who is Johann Ghostweaver and how is he connected to Oscar Yoren?', NULL, NULL, 'UNDISCOVERED', '', NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO "Quest" (id, "campaignId", title, description, "giverId", reward, status, notes, "createdAt") VALUES ('q-dk-4', 'campaign-drakkenheim', 'Hooded Lanterns Quest — Infected Potions', 'A quest from the Hooded Lanterns involving infected potions at the estate near Eckerman Mill.', 'npc-karin-alsberg', NULL, 'ACTIVE', 'Estate near Eckerman Mill. Not yet visited.', NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO "Quest" (id, "campaignId", title, description, "giverId", reward, status, notes, "createdAt") VALUES ('q-dk-5', 'campaign-drakkenheim', 'Contact Black Jack', 'Black Jack at the Hanging Lock tavern — a contact from the Queen''s Men.', 'npc-madam-rochelle', NULL, 'ACTIVE', 'Tiflings ''Deceit and Lies'' mentioned Black Jack can offer work for the Queen.', NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO "Quest" (id, "campaignId", title, description, "giverId", reward, status, notes, "createdAt") VALUES ('q-dk-6', 'campaign-drakkenheim', 'Retrieve Aldor''s Research', 'Aldor had collected field notes on Haze mutation patterns in the Outer City. His research was stored at the Red Lion Hotel.', 'npc-aldor', NULL, 'UNAVAILABLE', 'Aldor was killed by the Mind Reaper. The Red Lion is still accessible — research may still be there.', NOW()) ON CONFLICT (id) DO NOTHING;
